import{_ as e,c as l,o as t,ag as i}from"./chunks/framework.ELrfyV9R.js";const u=JSON.parse('{"title":"二、用最通俗的话理解：飞书发来一条消息后，到底发生了什么","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/openclaw如何运行的.md","filePath":"ai/2026-03/openclaw如何运行的.md","lastUpdated":1773707651000}'),o={name:"ai/2026-03/openclaw如何运行的.md"};function p(r,a,n,h,s,d){return t(),l("div",null,a[0]||(a[0]=[i('<p>可以把 <strong>Gateway</strong> 理解成 OpenClaw 的“总调度中心”。</p><p>你在飞书里发一句话，看起来只是“消息进来，AI回一句”，但 Gateway 在中间其实做了很多事：<strong>接消息、判断交给谁、排队、找上下文、驱动 Agent 干活、再把结果发回去</strong>。<br> 下面我按“先整体，再走一遍飞书消息链路”的方式，给你重新梳理。</p><hr><h1 id="二、用最通俗的话理解-飞书发来一条消息后-到底发生了什么" tabindex="-1">二、用最通俗的话理解：飞书发来一条消息后，到底发生了什么 <a class="header-anchor" href="#二、用最通俗的话理解-飞书发来一条消息后-到底发生了什么" aria-label="Permalink to &quot;二、用最通俗的话理解：飞书发来一条消息后，到底发生了什么&quot;">​</a></h1><p>假设你在飞书里发了一句：</p><blockquote><p>帮我查一下今天的股票行情</p></blockquote><p>从你点击发送，到 OpenClaw 回复再返回到你的飞书，中间大致要经过 <strong>6 步</strong>。</p><hr><h2 id="第-1-步-飞书把消息交给-gateway" tabindex="-1">第 1 步：飞书把消息交给 Gateway <a class="header-anchor" href="#第-1-步-飞书把消息交给-gateway" aria-label="Permalink to &quot;第 1 步：飞书把消息交给 Gateway&quot;">​</a></h2><p>你在飞书里发了个消息，消息会先发送到飞书的服务器。<br> 然后飞书通过插件，把这条消息推送给你部署的OpenClaw的Gateway。</p><p>这时 Gateway 拿到的，不只是文字本身，还会拿到一堆“附带信息”，比如：</p><ul><li><p>这是哪个渠道来的：飞书</p></li><li><p>是谁发的</p></li><li><p>是私聊还是群聊</p></li><li><p>群 ID / 用户 ID 是多少</p></li><li><p>目标 bot 账号是谁</p></li><li><p>消息内容是什么</p></li></ul><p>你可以把这一步理解成：</p><p><strong>Gateway 先当“前台接待员”，把外部世界送来的消息接收进来，并拆成结构化信息。</strong></p><hr><h2 id="第-2-步-gateway-判断这条消息该交给哪个-agent" tabindex="-1">第 2 步：Gateway 判断这条消息该交给哪个 Agent <a class="header-anchor" href="#第-2-步-gateway-判断这条消息该交给哪个-agent" aria-label="Permalink to &quot;第 2 步：Gateway 判断这条消息该交给哪个 Agent&quot;">​</a></h2><p>消息到了以后，不是马上就给 AI。<br> Gateway 会先判断：</p><blockquote><p>这条消息应该由谁来处理？</p></blockquote><p>比如你可能配置过：</p><ul><li><p>飞书私聊 → main Agent</p></li><li><p>某个写作群 → writer Agent</p></li><li><p>某个Code群 → code Agent</p></li></ul><p>这一步是<strong>规则匹配</strong>，不是让模型去猜。</p><p>也就是说，Gateway 会根据配置看：</p><ul><li><p>来自哪个渠道</p></li><li><p>哪个账号</p></li><li><p>私聊还是群聊</p></li><li><p>是哪个具体群</p></li><li><p>是否线程继承上一个上下文</p></li></ul><p>然后用最精确的规则去匹配目标 Agent。</p><h3 id="为什么这样设计很聪明" tabindex="-1">为什么这样设计很聪明 <a class="header-anchor" href="#为什么这样设计很聪明" aria-label="Permalink to &quot;为什么这样设计很聪明&quot;">​</a></h3><p>因为它有三个优点：</p><h4 id="_1-稳定" tabindex="-1">1. 稳定 <a class="header-anchor" href="#_1-稳定" aria-label="Permalink to &quot;1. 稳定&quot;">​</a></h4><p>不会今天 AI 觉得该给 main，明天又觉得该给 writer。</p><h4 id="_2-快" tabindex="-1">2. 快 <a class="header-anchor" href="#_2-快" aria-label="Permalink to &quot;2. 快&quot;">​</a></h4><p>不用先额外跑一次模型来做“路由判断”。</p><h4 id="_3-省钱" tabindex="-1">3. 省钱 <a class="header-anchor" href="#_3-省钱" aria-label="Permalink to &quot;3. 省钱&quot;">​</a></h4><p>不消耗额外 token。</p><p>所以这一步你可以理解成：</p><p><strong>Gateway 像分诊台，先把病人分到正确科室，而不是让 AI 自己猜该挂哪个号。</strong></p><hr><h2 id="第-3-步-消息先排队-而不是立刻执行" tabindex="-1">第 3 步：消息先排队，而不是立刻执行 <a class="header-anchor" href="#第-3-步-消息先排队-而不是立刻执行" aria-label="Permalink to &quot;第 3 步：消息先排队，而不是立刻执行&quot;">​</a></h2><p>确定交给哪个 Agent 后，Gateway 通常也不会马上开始处理，而是先进入队列。</p><p>为什么要排队？</p><p>因为同一个 Session 里，通常只能有一个 Agent 正在运行。<br> 否则会乱。</p><p>比如你连续发三句：</p><ol><li><p>帮我查今天日志</p></li><li><p>顺便看下数据库状态</p></li><li><p>如果有异常发我摘要</p></li></ol><p>如果三条同时并行跑，可能会出现：</p><ul><li><p>第二条没等第一条结果</p></li><li><p>第三条不知道前两条执行到了哪</p></li><li><p>工具操作互相打架</p></li></ul><p>所以 Gateway 采取的思路是：</p><ul><li><p><strong>不同会话可以并行</strong></p></li><li><p><strong>同一个会话内部严格串行</strong></p></li></ul><p>这就像餐厅后厨：</p><ul><li><p>不同桌的单子可以同时做</p></li><li><p>但同一桌加单，得按顺序处理，避免前后逻辑错乱</p></li></ul><h3 id="队列还有几种模式" tabindex="-1">队列还有几种模式 <a class="header-anchor" href="#队列还有几种模式" aria-label="Permalink to &quot;队列还有几种模式&quot;">​</a></h3><p>文章里提到 collect、steer、followup 等模式。通俗说：</p><ul><li><p><strong>collect</strong>：把短时间内来的多条消息合并一下再处理</p></li><li><p><strong>followup</strong>：老老实实排在后面等</p></li><li><p><strong>steer</strong>：当前 AI 正在干活时，你插一句补充要求，它能在合适时机“插入”当前运行流程</p></li></ul><p>其中 steer 很像：</p><blockquote><p>AI 正在埋头做事，你从旁边补一句：“对了，优先查 error 日志。”</p></blockquote><p>它不是完全打断，而是在下一个合适节点把你的补充塞进去。</p><hr><h2 id="第-4-步-gateway-找到这条消息属于哪个-session" tabindex="-1">第 4 步：Gateway 找到这条消息属于哪个 Session <a class="header-anchor" href="#第-4-步-gateway-找到这条消息属于哪个-session" aria-label="Permalink to &quot;第 4 步：Gateway 找到这条消息属于哪个 Session&quot;">​</a></h2><p>这里是最容易被忽略，但实际非常关键的一步。</p><p><strong>Session = 这次对话所属的上下文容器。</strong></p><p>Agent 回答问题，不是只看“这一句”，而是看这句话属于哪段对话、接着谁的上下文说。</p><p>Gateway 会判断：</p><ul><li><p>这是私聊吗？</p></li><li><p>是某个群吗？</p></li><li><p>是哪个用户？</p></li><li><p>是否要跨渠道复用上下文？</p></li><li><p>是否该新开一个 Session？</p></li><li><p>这个旧 Session 是否已经过期？</p></li></ul><h3 id="举几个例子" tabindex="-1">举几个例子 <a class="header-anchor" href="#举几个例子" aria-label="Permalink to &quot;举几个例子&quot;">​</a></h3><h4 id="情况-1-你自己一个人用" tabindex="-1">情况 1：你自己一个人用 <a class="header-anchor" href="#情况-1-你自己一个人用" aria-label="Permalink to &quot;情况 1：你自己一个人用&quot;">​</a></h4><p>可能飞书私聊、Telegram 私聊、WebChat 私聊，全都汇入同一个主 Session。<br> 这样你在飞书说了一半，去 Telegram 接着聊，也能连续上。</p><h4 id="情况-2-多人共用一个-bot" tabindex="-1">情况 2：多人共用一个 bot <a class="header-anchor" href="#情况-2-多人共用一个-bot" aria-label="Permalink to &quot;情况 2：多人共用一个 bot&quot;">​</a></h4><p>那通常会按“每个用户单独隔离”来建 Session。<br> 否则 A 说的话会混到 B 的上下文里。</p><h4 id="情况-3-群聊" tabindex="-1">情况 3：群聊 <a class="header-anchor" href="#情况-3-群聊" aria-label="Permalink to &quot;情况 3：群聊&quot;">​</a></h4><p>群聊天然按群隔离。<br> 这个群一个 Session，另一个群另一个 Session。</p><h3 id="session-还会重置" tabindex="-1">Session 还会重置 <a class="header-anchor" href="#session-还会重置" aria-label="Permalink to &quot;Session 还会重置&quot;">​</a></h3><p>比如：</p><ul><li><p>每天凌晨 4 点后开新上下文</p></li><li><p>空闲 30 分钟后重置</p></li><li><p>你手动发 <code>/new</code> 或 <code>/reset</code></p></li></ul><p>注意，这种“重置”不是删记录，而是：</p><ul><li><p>旧的归档</p></li><li><p>新的开始</p></li></ul><p>就像翻到新的一页，但旧笔记还保留着。</p><p>所以这一步可以理解成：</p><p><strong>Gateway 在给消息找“它应该接在哪段对话后面”。</strong></p><hr><h2 id="第-5-步-真正进入-agent-loop-ai-开始干活" tabindex="-1">第 5 步：真正进入 Agent Loop，AI 开始干活 <a class="header-anchor" href="#第-5-步-真正进入-agent-loop-ai-开始干活" aria-label="Permalink to &quot;第 5 步：真正进入 Agent Loop，AI 开始干活&quot;">​</a></h2><p>到了这里，消息才真正交给 Agent。</p><p>这时 Gateway 会做一件非常关键的事：<strong>组装上下文</strong>。</p><p>AI 并不是拿着一句“帮我查日志有没有异常”就直接开始回答。<br> Gateway 会把很多东西一起塞进去，构成完整认知环境。</p><p>通常包括：</p><ul><li><p><strong>SOUL.md</strong>：这个 Agent 是谁，性格、边界、说话风格</p></li><li><p><strong>USER.md</strong>：你是谁、你的习惯和偏好</p></li><li><p><strong>AGENTS.md</strong>：这个 Agent 有什么能力</p></li><li><p><strong>MEMORY.md</strong>：长期记忆（一般只在私聊场景加载）</p></li><li><p><strong>今天/昨天的日记</strong></p></li><li><p><strong>Skills 快照</strong></p></li><li><p><strong>历史对话</strong></p></li><li><p><strong>这条新消息</strong></p></li></ul><p>然后进入标准的 Agent Loop：</p><h3 id="agent-loop-通俗版" tabindex="-1">Agent Loop 通俗版 <a class="header-anchor" href="#agent-loop-通俗版" aria-label="Permalink to &quot;Agent Loop 通俗版&quot;">​</a></h3><ol><li><p>把上下文全部准备好</p></li><li><p>把新消息放进对话历史</p></li><li><p>调用大模型开始思考</p></li><li><p>如果模型觉得要用工具，就去调用工具</p></li><li><p>工具返回结果后，再交给模型继续想</p></li><li><p>重复这个过程，直到模型产出最终回答</p></li><li><p>把回答流式发出去</p></li></ol><p>比如你说“查日志有没有异常”，模型可能会决定：</p><ul><li><p>先调用 read / grep / exec 之类工具</p></li><li><p>读取日志</p></li><li><p>分析异常模式</p></li><li><p>整理成摘要</p></li><li><p>最后回复你</p></li></ul><h3 id="为什么你会看到-ai-正在输入" tabindex="-1">为什么你会看到“AI 正在输入” <a class="header-anchor" href="#为什么你会看到-ai-正在输入" aria-label="Permalink to &quot;为什么你会看到“AI 正在输入”&quot;">​</a></h3><p>因为 Gateway 用的是“两阶段响应”思路：</p><h4 id="第一阶段-立刻确认收到" tabindex="-1">第一阶段：立刻确认收到 <a class="header-anchor" href="#第一阶段-立刻确认收到" aria-label="Permalink to &quot;第一阶段：立刻确认收到&quot;">​</a></h4><p>Gateway 先告诉客户端：</p><blockquote><p>收到了，已经开始处理</p></blockquote><p>所以飞书可以先显示“正在输入”。</p><h4 id="第二阶段-边处理边推送结果" tabindex="-1">第二阶段：边处理边推送结果 <a class="header-anchor" href="#第二阶段-边处理边推送结果" aria-label="Permalink to &quot;第二阶段：边处理边推送结果&quot;">​</a></h4><p>Agent 干活的过程中，工具调用、文本生成、最终结果，会通过 WebSocket 流式推送出去。</p><p>所以你看到的不是“等很久突然冒出整段话”，而是：</p><ul><li><p>先显示在处理中</p></li><li><p>然后回复一点点出现</p></li><li><p>最后完整结束</p></li></ul><p>这一步你可以理解成：</p><p><strong>Gateway 像项目经理，把资料准备好，叫 Agent 开工，必要时调工具，再把产出一点点往外送。</strong></p><hr><h2 id="第-6-步-把-ai-回复发回飞书" tabindex="-1">第 6 步：把 AI 回复发回飞书 <a class="header-anchor" href="#第-6-步-把-ai-回复发回飞书" aria-label="Permalink to &quot;第 6 步：把 AI 回复发回飞书&quot;">​</a></h2><p>当 Agent 生成回复以后，Gateway 还不能直接原样扔回去。<br> 它还要经过“渠道适配”。</p><p>因为不同渠道的消息格式不一样：</p><ul><li><p>飞书有飞书的消息格式</p></li><li><p>Telegram 有 Telegram 的格式</p></li><li><p>Discord 有 Discord 的格式</p></li></ul><p>所以 Gateway 会把 Agent 生成的内容，交给飞书对应的渠道插件做转换，然后再通过飞书连接发回去。</p><p>最终你在飞书里看到的，就是处理后的回复。</p><p>如果是长回复，还可能边生成边分块发送。<br> 所以你看到的“逐渐出现”，本质上就是：</p><p><strong>模型在生成，Gateway 在转发，飞书在展示。</strong></p><hr><h1 id="三、把整个过程压缩成一条最容易懂的链路" tabindex="-1">三、把整个过程压缩成一条最容易懂的链路 <a class="header-anchor" href="#三、把整个过程压缩成一条最容易懂的链路" aria-label="Permalink to &quot;三、把整个过程压缩成一条最容易懂的链路&quot;">​</a></h1><p>你可以直接记这一版：</p><h3 id="飞书发消息-→-gateway-收到-→-判断交给哪个-agent-→-排队-→-找到对应-session-→-组装上下文-→-agent-调模型和工具干活-→-结果流式返回-→-gateway-转成飞书格式-→-发回飞书" tabindex="-1">飞书发消息 → Gateway 收到 → 判断交给哪个 Agent → 排队 → 找到对应 Session → 组装上下文 → Agent 调模型和工具干活 → 结果流式返回 → Gateway 转成飞书格式 → 发回飞书 <a class="header-anchor" href="#飞书发消息-→-gateway-收到-→-判断交给哪个-agent-→-排队-→-找到对应-session-→-组装上下文-→-agent-调模型和工具干活-→-结果流式返回-→-gateway-转成飞书格式-→-发回飞书" aria-label="Permalink to &quot;飞书发消息 → Gateway 收到 → 判断交给哪个 Agent → 排队 → 找到对应 Session → 组装上下文 → Agent 调模型和工具干活 → 结果流式返回 → Gateway 转成飞书格式 → 发回飞书&quot;">​</a></h3><p>这就是最核心的一条链。</p><hr><h1 id="四、再用一个生活化比喻讲一遍" tabindex="-1">四、再用一个生活化比喻讲一遍 <a class="header-anchor" href="#四、再用一个生活化比喻讲一遍" aria-label="Permalink to &quot;四、再用一个生活化比喻讲一遍&quot;">​</a></h1><p>把 Gateway 想成一家餐厅的“总控台”，会更好懂。</p><h3 id="你在飞书发消息" tabindex="-1">你在飞书发消息 <a class="header-anchor" href="#你在飞书发消息" aria-label="Permalink to &quot;你在飞书发消息&quot;">​</a></h3><p>相当于顾客进店点单。</p><h3 id="channel-接收" tabindex="-1">Channel 接收 <a class="header-anchor" href="#channel-接收" aria-label="Permalink to &quot;Channel 接收&quot;">​</a></h3><p>前台先把单子收下来，识别你是谁、在哪桌、点了什么。</p><h3 id="路由" tabindex="-1">路由 <a class="header-anchor" href="#路由" aria-label="Permalink to &quot;路由&quot;">​</a></h3><p>前台判断这单该给哪个厨师：</p><ul><li><p>家常菜给 main</p></li><li><p>写作类给 writer</p></li><li><p>运维类给 ops</p></li></ul><h3 id="队列" tabindex="-1">队列 <a class="header-anchor" href="#队列" aria-label="Permalink to &quot;队列&quot;">​</a></h3><p>后厨不是每张单都立刻做，要按桌次和优先级排队，避免同一桌菜乱套。</p><h3 id="session" tabindex="-1">Session <a class="header-anchor" href="#session" aria-label="Permalink to &quot;Session&quot;">​</a></h3><p>总控台确认这张单属于哪一桌、接的是哪一轮菜。</p><h3 id="agent-loop" tabindex="-1">Agent Loop <a class="header-anchor" href="#agent-loop" aria-label="Permalink to &quot;Agent Loop&quot;">​</a></h3><p>厨师开始做菜：</p><ul><li><p>看菜单</p></li><li><p>看你之前点过什么</p></li><li><p>看这桌口味偏好</p></li><li><p>需要时去仓库拿材料（调用工具）</p></li><li><p>最后把菜做好</p></li></ul><h3 id="回复发送" tabindex="-1">回复发送 <a class="header-anchor" href="#回复发送" aria-label="Permalink to &quot;回复发送&quot;">​</a></h3><p>服务员把菜端回你桌上，也就是把回复发回飞书。</p><p>所以 Gateway 本质上就是：</p><p><strong>前台 + 调度台 + 后厨总控 + 配送中枢</strong></p><hr><h1 id="五、websocket-在这里是干什么的" tabindex="-1">五、WebSocket 在这里是干什么的 <a class="header-anchor" href="#五、websocket-在这里是干什么的" aria-label="Permalink to &quot;五、WebSocket 在这里是干什么的&quot;">​</a></h1><p>文章里还讲了 WebSocket 协议，这部分你可以这样理解：</p><p>Gateway 和外部客户端（比如 WebChat、CLI、macOS App、Node 设备）之间，不是每次都重新发 HTTP 请求，而是保持一条<strong>长连接</strong>。</p><p>这条长连接有几个作用：</p><h3 id="_1-建立连接后马上做身份确认" tabindex="-1">1. 建立连接后马上做身份确认 <a class="header-anchor" href="#_1-建立连接后马上做身份确认" aria-label="Permalink to &quot;1. 建立连接后马上做身份确认&quot;">​</a></h3><p>谁连进来了？<br> 你是 operator 还是 node？<br> 有没有权限？<br> 是不是已配对设备？</p><h3 id="_2-可以双向实时通信" tabindex="-1">2. 可以双向实时通信 <a class="header-anchor" href="#_2-可以双向实时通信" aria-label="Permalink to &quot;2. 可以双向实时通信&quot;">​</a></h3><p>客户端可以发请求给 Gateway，Gateway 也可以主动推事件。</p><h3 id="_3-适合流式结果" tabindex="-1">3. 适合流式结果 <a class="header-anchor" href="#_3-适合流式结果" aria-label="Permalink to &quot;3. 适合流式结果&quot;">​</a></h3><p>AI 回复不是一次性返回，而是边生成边推。<br> WebSocket 天然适合这种实时交互。</p><h3 id="_4-适合设备在线管理" tabindex="-1">4. 适合设备在线管理 <a class="header-anchor" href="#_4-适合设备在线管理" aria-label="Permalink to &quot;4. 适合设备在线管理&quot;">​</a></h3><p>比如手机、电脑、树莓派这些 Node 设备连上来后，可以持续声明：</p><ul><li><p>我有摄像头</p></li><li><p>我能录屏</p></li><li><p>我能定位</p></li><li><p>我能执行某些命令</p></li></ul><p>Gateway 就能统一调度它们。</p><p>所以 WebSocket 在 Gateway 里的角色，可以理解成：</p><p><strong>一根一直不断开的实时通信管道。</strong></p><hr><h1 id="六、为什么说-gateway-不是黑盒" tabindex="-1">六、为什么说 Gateway 不是黑盒 <a class="header-anchor" href="#六、为什么说-gateway-不是黑盒" aria-label="Permalink to &quot;六、为什么说 Gateway 不是黑盒&quot;">​</a></h1><p>理解完上面这条链路之后，你排查问题就有方向了。</p><h3 id="_1-收不到消息" tabindex="-1">1. 收不到消息 <a class="header-anchor" href="#_1-收不到消息" aria-label="Permalink to &quot;1. 收不到消息&quot;">​</a></h3><p>先看 Channel 层。<br> 可能是飞书插件没接好，或者 WebSocket 断了。</p><h3 id="_2-消息进来了-但跑错-agent" tabindex="-1">2. 消息进来了，但跑错 Agent <a class="header-anchor" href="#_2-消息进来了-但跑错-agent" aria-label="Permalink to &quot;2. 消息进来了，但跑错 Agent&quot;">​</a></h3><p>看路由配置 binding。<br> 多半是匹配规则没写对。</p><h3 id="_3-回复特别慢" tabindex="-1">3. 回复特别慢 <a class="header-anchor" href="#_3-回复特别慢" aria-label="Permalink to &quot;3. 回复特别慢&quot;">​</a></h3><p>可能有两种原因：</p><ul><li><p>队列里前面还有消息在排</p></li><li><p>Agent 推理 / 工具执行本身比较慢</p></li></ul><h3 id="_4-上下文接不上" tabindex="-1">4. 上下文接不上 <a class="header-anchor" href="#_4-上下文接不上" aria-label="Permalink to &quot;4. 上下文接不上&quot;">​</a></h3><p>看 Session 定位和重置策略。<br> 可能 Session 被重置了，或者隔离范围配错了。</p><h3 id="_5-ai-回了-但飞书没显示" tabindex="-1">5. AI 回了，但飞书没显示 <a class="header-anchor" href="#_5-ai-回了-但飞书没显示" aria-label="Permalink to &quot;5. AI 回了，但飞书没显示&quot;">​</a></h3><p>看回复发送链路。<br> 可能是渠道插件格式转换或发送出了问题。</p><p>也就是说，Gateway 一旦拆开看，它其实不是神秘黑盒，而是一条很清楚的流水线。</p><hr><h1 id="七、给你一个更适合讲给别人听的-精简版" tabindex="-1">七、给你一个更适合讲给别人听的“精简版” <a class="header-anchor" href="#七、给你一个更适合讲给别人听的-精简版" aria-label="Permalink to &quot;七、给你一个更适合讲给别人听的“精简版”&quot;">​</a></h1><p>你要是想用很通俗的话对别人解释，可以直接这么说：</p><blockquote><p>OpenClaw 里的 Gateway，就像整个系统的总调度中心。<br> 飞书消息一来，先由 Gateway 接住；然后它根据规则判断该交给哪个 Agent；接着把消息排进队列，找到对应的对话上下文 Session；再把人格、记忆、历史对话、工具能力等上下文组装好，驱动 Agent 去调用模型和工具处理；最后把生成结果通过飞书插件转成飞书能显示的格式，再发回飞书。<br> 整个过程中，Gateway 还负责消息路由、会话隔离、并发控制、流式回复、设备管理和定时任务，所以它其实是 OpenClaw 的核心中枢，而不只是“跑 Agent 的地方”。</p></blockquote><hr><h1 id="八、最后帮你做一个-飞书消息往返-的超简流程图版" tabindex="-1">八、最后帮你做一个“飞书消息往返”的超简流程图版 <a class="header-anchor" href="#八、最后帮你做一个-飞书消息往返-的超简流程图版" aria-label="Permalink to &quot;八、最后帮你做一个“飞书消息往返”的超简流程图版&quot;">​</a></h1><h3 id="飞书发消息" tabindex="-1">飞书发消息 <a class="header-anchor" href="#飞书发消息" aria-label="Permalink to &quot;飞书发消息&quot;">​</a></h3><p>↓</p><h3 id="gateway-收消息" tabindex="-1">Gateway 收消息 <a class="header-anchor" href="#gateway-收消息" aria-label="Permalink to &quot;Gateway 收消息&quot;">​</a></h3><p>识别渠道、用户、群/私聊、内容<br> ↓</p><h3 id="路由-1" tabindex="-1">路由 <a class="header-anchor" href="#路由-1" aria-label="Permalink to &quot;路由&quot;">​</a></h3><p>判断交给哪个 Agent<br> ↓</p><h3 id="队列-1" tabindex="-1">队列 <a class="header-anchor" href="#队列-1" aria-label="Permalink to &quot;队列&quot;">​</a></h3><p>同一 Session 串行，避免冲突<br> ↓</p><h3 id="session-定位" tabindex="-1">Session 定位 <a class="header-anchor" href="#session-定位" aria-label="Permalink to &quot;Session 定位&quot;">​</a></h3><p>找到这条消息所属对话上下文<br> ↓</p><h3 id="agent-loop-1" tabindex="-1">Agent Loop <a class="header-anchor" href="#agent-loop-1" aria-label="Permalink to &quot;Agent Loop&quot;">​</a></h3><p>组装上下文 → 调模型 → 调工具 → 生成回复<br> ↓</p><h3 id="流式输出" tabindex="-1">流式输出 <a class="header-anchor" href="#流式输出" aria-label="Permalink to &quot;流式输出&quot;">​</a></h3><p>处理中、生成中、完成<br> ↓</p><h3 id="渠道适配" tabindex="-1">渠道适配 <a class="header-anchor" href="#渠道适配" aria-label="Permalink to &quot;渠道适配&quot;">​</a></h3><p>转成飞书格式<br> ↓</p><h3 id="发回飞书" tabindex="-1">发回飞书 <a class="header-anchor" href="#发回飞书" aria-label="Permalink to &quot;发回飞书&quot;">​</a></h3><hr><p>如果你需要，我可以下一步直接帮你整理成一版 <strong>更适合发公众号/知识星球的“口语化重写稿”</strong>，或者画成 <strong>一张结构图说明稿</strong>。</p>',191)]))}const c=e(o,[["render",p]]);export{u as __pageData,c as default};
